import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getMyChangeRequests } from '../../services/dataService';
import { formatDate } from '../../utils/helpers';
import StatusBadge from '../../components/common/StatusBadge';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import { FiPlus } from 'react-icons/fi';

const CustomerChangeRequests = () => {
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetch = async () => {
      try {
        const res = await getMyChangeRequests();
        setRequests(res.data.data);
      } catch (err) { console.error(err); }
      finally { setLoading(false); }
    };
    fetch();
  }, []);

  if (loading) return <LoadingSpinner />;

  return (
    <div>
      <div className="page-header">
        <h1>🔧 Submit Maintenance Request</h1>
        <Link to="/customer/change-requests/new" className="btn btn-primary"><FiPlus /> New Request</Link>
      </div>

      {requests.length === 0 ? (
        <div className="empty-state"><p>No maintenance requests yet</p></div>
      ) : (
        <div className="table-container">
          <table>
            <thead><tr><th>Title</th><th>Type</th><th>Property</th><th>Priority</th><th>Status</th><th>Date</th></tr></thead>
            <tbody>
              {requests.map(r => (
                <tr key={r._id}>
                  <td>{r.title}</td>
                  <td>{r.type}</td>
                  <td>{r.property?.title || 'N/A'}</td>
                  <td><StatusBadge status={r.priority} /></td>
                  <td><StatusBadge status={r.status} /></td>
                  <td>{formatDate(r.createdAt)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default CustomerChangeRequests;
